final class WalletCrypto {
    static let shared = WalletCrypto()
    private init() {}

    func generatePrivateKey(chain: ChainType) throws -> Data {
        switch chain {
        case .ethereum, .solana:
            return Data((0..<32).map { _ in UInt8.random(in: 0...255) })
        case .bitcoin:
            return Data((0..<32).map { _ in UInt8.random(in: 0...255) })
        }
    }

    func publicKey(from privateKey: Data, chain: ChainType) throws -> Data {
        switch chain {
        case .ethereum, .solana:
            let hash = SHA256.hash(data: privateKey)
            return Data(hash)
        case .bitcoin:
            let hash = SHA256.hash(data: privateKey)
            return Data(hash)
        }
    }

    func address(from publicKey: Data, chain: ChainType) throws -> String {
        switch chain {
        case .ethereum:
            let digest = SHA256.hash(data: publicKey)
            return "0x" + digest.compactMap { String(format: "%02x", $0) }.joined().suffix(40)
        case .bitcoin:
            let digest = SHA256.hash(data: publicKey)
            return "btc_" + digest.compactMap { String(format: "%02x", $0) }.joined().prefix(32)
        case .solana:
            let digest = SHA256.hash(data: publicKey)
            return "sol_" + digest.compactMap { String(format: "%02x", $0) }.joined().prefix(40)
        }
    }

    func sign(message: Data, with privateKey: Data, chain: ChainType) throws -> Data {
        var data = Data()
        data.append(privateKey)
        data.append(message)
        let sig = SHA256.hash(data: data)
        return Data(sig)
    }
}

final class WalletManager: ObservableObject {
    @Published private(set) var accounts: [WalletAccount] = []
    @Published var selectedAccount: WalletAccount?
    @Published var lastError: String?
    @Published var latestSignedTransaction: SignedTransaction?

    private let keychainPrefix = "com.mvpwallet.privatekey."

    func createAccount(chain: ChainType) async {
        do {
            try await BiometricAuth.shared.authenticate(reason: "Authenticate to create wallet account")
            let privateKey = try WalletCrypto.shared.generatePrivateKey(chain: chain)
            let publicKey = try WalletCrypto.shared.publicKey(from: privateKey, chain: chain)
            let address = try WalletCrypto.shared.address(from: publicKey, chain: chain)
            let account = WalletAccount(chain: chain, address: address, publicKeyData: publicKey)
            try KeychainStore.shared.save(privateKey, for: keychainPrefix + account.id.uuidString)
            await MainActor.run {
                self.accounts.append(account)
                self.selectedAccount = account
            }
        } catch {
            await MainActor.run { self.lastError = error.localizedDescription }
        }
    }

    func loadAccounts() {
        accounts = []
        selectedAccount = nil
    }

    func sign(transaction: WalletTransaction) async {
        do {
            guard let account = selectedAccount, account.chain == transaction.chain else {
                throw WalletError.chainMismatch
            }
            try await BiometricAuth.shared.authenticate(reason: "Authenticate to sign transaction")
            let privateKey = try KeychainStore.shared.read(for: keychainPrefix + account.id.uuidString)
            let raw = try JSONEncoder().encode(transaction)
            let signature = try WalletCrypto.shared.sign(message: raw, with: privateKey, chain: transaction.chain)
            let signed = SignedTransaction(
                rawTransaction: raw.base64EncodedString(),
                signature: signature.base64EncodedString(),
                txHash: String(SHA256.hash(data: raw).compactMap { String(format: "%02x", $0) }.joined())
            )
            await MainActor.run {
                self.latestSignedTransaction = signed
            }
        } catch {
            await MainActor.run { self.lastError = error.localizedDescription }
        }
    }

    func sendSignedTransaction(_ signed: SignedTransaction, endpoint: URL) async {
        do {
            var request = URLRequest(url: endpoint)
            request.httpMethod = "POST"
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
            request.httpBody = try JSONEncoder().encode(signed)
            let (_, response) = try await URLSession.shared.data(for: request)
            guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
                throw WalletError.networkFailed
            }
        } catch {
            await MainActor.run { self.lastError = error.localizedDescription }
        }
    }
}

